// Package testvectors verifies that the Go implementation produces
// byte-for-byte identical output to the published AAFP test vectors.
//
// This is the primary interoperability validation. If all vectors pass,
// the Go implementation produces canonical wire format compatible with
// the Rust reference implementation.
//
// Test vectors are from TEST_VECTORS.md, generated by the Rust implementation.
// The Go implementation was written from the RFCs alone and must reproduce
// each vector without consulting the Rust source.
package testvectors

import (
	"crypto/sha256"
	"encoding/binary"
	"encoding/hex"
	"testing"

	"aafp-go/cbor"
	aafperrors "aafp-go/errors"
	"aafp-go/frame"
	"aafp-go/handshake"
	"aafp-go/identity"
)

// Fixed test inputs from TEST_VECTORS.md
var (
	agentIDA     = bytes32(0x01)
	agentIDB     = bytes32(0x02)
	nonceA       = bytes32(0x03)
	nonceB       = bytes32(0x04)
	tlsBinding   = bytes32(0x05)
	sessionID    = bytes32(0x06)
	publicKeyA   = bytesN(0x42, 1952)
	publicKeyB   = bytesN(0x43, 1952)
	signatureA   = bytesN(0x44, 3309)
	signatureB   = bytesN(0x45, 3309)
	timestampNow = uint64(1735689600)
	timestampExp = uint64(1736294400)
)

func bytes32(b byte) []byte {
	v := make([]byte, 32)
	for i := range v {
		v[i] = b
	}
	return v
}

func bytesN(b byte, n int) []byte {
	v := make([]byte, n)
	for i := range v {
		v[i] = b
	}
	return v
}

func hexHash(b []byte) string {
	h := sha256.Sum256(b)
	return hex.EncodeToString(h[:])
}

// mustEncode encodes a CBOR value and returns its hex representation.
func mustEncode(t *testing.T, v cbor.Value) string {
	b, err := cbor.Encode(&v)
	if err != nil {
		t.Fatalf("CBOR encode failed: %v", err)
	}
	return hex.EncodeToString(b)
}

func mustEncodeBytes(t *testing.T, v cbor.Value) []byte {
	b, err := cbor.Encode(&v)
	if err != nil {
		t.Fatalf("CBOR encode failed: %v", err)
	}
	return b
}

