func TestCBORIntMapSorted(t *testing.T) {
	// {1: "a", 100: "b"} — key 1 (1 byte) before key 100 (2 bytes)
	v := cbor.IMap([]cbor.IntMapEntry{
		{Key: 1, Value: cbor.TStr("a")},
		{Key: 100, Value: cbor.TStr("b")},
	})
	got := mustEncode(t, v)
	want := "a201616118646162"
	if got != want {
		t.Errorf("int map sorted: got %s, want %s", got, want)
	}
}

func TestCBORIntMapSameLength(t *testing.T) {
	// {10: 1, 20: 2} — same-length keys sorted bytewise
	v := cbor.IMap([]cbor.IntMapEntry{
		{Key: 10, Value: cbor.UUint(1)},
		{Key: 20, Value: cbor.UUint(2)},
	})
	got := mustEncode(t, v)
	want := "a20a011402"
	if got != want {
		t.Errorf("int map same-length: got %s, want %s", got, want)
	}
}

func TestCBORStrMapSorted(t *testing.T) {
	// {"cat": 1, "apple": 2, "zebra": 3} — length-first
	v := cbor.SMap([]cbor.StrMapEntry{
		{Key: "cat", Value: cbor.UUint(1)},
		{Key: "apple", Value: cbor.UUint(2)},
		{Key: "zebra", Value: cbor.UUint(3)},
	})
	got := mustEncode(t, v)
	want := "a36363617401656170706c6502657a6562726103"
	if got != want {
		t.Errorf("str map sorted: got %s, want %s", got, want)
	}
}

