// === Handshake Structures ===

func TestHandshakeClientHelloWithoutSig(t *testing.T) {
	ch := &handshake.ClientHello{
		ProtocolVersion: 1,
		AgentId:         agentIDA,
		PublicKey:       publicKeyA,
		Nonce:           nonceA,
		Capabilities:    []cbor.Value{},
		Extensions:      []handshake.ExtensionEntry{},
		ExpiresAt:       timestampExp,
		KeyAlgorithm:    1,
	}
	cborVal := ch.ToCBORWithoutSigAndMac()
	b := mustEncodeBytes(t, cborVal)
	gotHash := hexHash(b)
	wantHash := "ac5bb0f3107963c9c2c6850f59323cd1f9b3666832d439010410e8115a98d0dc"
	if gotHash != wantHash {
		t.Errorf("ClientHello without sig:\n  got  hash: %s\n  want hash: %s\n  got  bytes: %s",
			gotHash, wantHash, hex.EncodeToString(b))
	}
}

