func TestDiscoveryAnnounceParams(t *testing.T) {
	// Announce params: {1: AgentRecord}
	// AgentRecord has capability "inference" (no metadata), endpoint, and signature A
	r := &identity.AgentRecord{
		RecordType: identity.RecordTypeV1,
		AgentId:    identity.AgentIdFromPubkey(publicKeyA),
		PublicKey:  publicKeyA,
		Capabilities: []identity.CapabilityDescriptor{
			{Name: "inference"},
		},
		Endpoints:    []string{"/ip4/127.0.0.1/tcp/4001"},
		CreatedAt:    timestampNow,
		ExpiresAt:    timestampExp,
		Signature:    signatureA,
		KeyAlgorithm: identity.KeyAlgMLDSA65,
	}
	recordCBOR := r.ToCBOR()
	params := cbor.IMap([]cbor.IntMapEntry{
		{Key: 1, Value: recordCBOR},
	})
	b := mustEncodeBytes(t, params)
	gotHash := hexHash(b)
	wantHash := "7dbdeddac0729c9734204c454b711c1a43762d02157385e53f7b0e0e0794ed40"
	if gotHash != wantHash {
		t.Errorf("announce params:\n  got  hash: %s\n  want hash: %s",
			gotHash, wantHash)
	}
}

// === Round-trip tests ===

func TestCBORRoundTrip(t *testing.T) {
	original := cbor.IMap([]cbor.IntMapEntry{
		{Key: 1, Value: cbor.UUint(42)},
		{Key: 2, Value: cbor.TStr("hello")},
		{Key: 100, Value: cbor.BStr([]byte{1, 2, 3})},
	})
	encoded, err := cbor.Encode(&original)
	if err != nil {
		t.Fatal(err)
	}
	decoded, n, err := cbor.Decode(encoded)
	if err != nil {
		t.Fatal(err)
	}
	if n != len(encoded) {
		t.Errorf("round-trip: consumed %d, expected %d", n, len(encoded))
	}
	if decoded.Kind() != cbor.KindIntMap {
		t.Fatalf("round-trip: expected int map, got %d", decoded.Kind())
	}
	if v := decoded.IntMapGet(1); v == nil || v.Uint() != 42 {
		t.Error("round-trip: key 1 mismatch")
	}
	if v := decoded.IntMapGet(2); v == nil || v.Str() != "hello" {
		t.Error("round-trip: key 2 mismatch")
	}
}

func TestFrameRoundTrip(t *testing.T) {
	original := &frame.Frame{
		Version:    frame.Version,
		FrameType:  frame.TypeData,
		Flags:      frame.FlagMore,
		StreamID:   42,
		Extensions: []byte{0xaa, 0xbb},
		Payload:    []byte{0xde, 0xad, 0xbe, 0xef},
	}
	encoded, err := frame.Encode(original)
	if err != nil {
		t.Fatal(err)
	}
	decoded, n, err := frame.Decode(encoded)
	if err != nil {
		t.Fatal(err)
	}
	if n != len(encoded) {
		t.Errorf("round-trip: consumed %d, expected %d", n, len(encoded))
	}
	if decoded.StreamID != 42 {
		t.Errorf("round-trip: stream ID %d, expected 42", decoded.StreamID)
	}
	if decoded.Flags != frame.FlagMore {
		t.Errorf("round-trip: flags 0x%02x, expected 0x%02x", decoded.Flags, frame.FlagMore)
	}
}

// === Negative tests ===

func TestFrameRejectOversizedPayload(t *testing.T) {
	// Frame with payload length > MaxPayloadSize should be rejected
	header := make([]byte, frame.HeaderSize)
	header[0] = frame.Version
	header[1] = frame.TypeData
	// Set payload length to MaxPayloadSize + 1
	binary.BigEndian.PutUint64(header[12:20], uint64(frame.MaxPayloadSize+1))
	_, _, err := frame.Decode(header)
	if err == nil {
		t.Error("should reject oversized payload")
	}
}

func TestFrameRejectOverflow(t *testing.T) {
	// Frame with ext_len + payload_len that overflows uint64
	header := make([]byte, frame.HeaderSize)
	header[0] = frame.Version
	header[1] = frame.TypeData
	binary.BigEndian.PutUint64(header[12:20], ^uint64(0)) // max payload
	binary.BigEndian.PutUint64(header[20:28], 1)          // 1 byte ext
	_, _, err := frame.Decode(header)
	if err == nil {
		t.Error("should reject length overflow")
	}
}

func TestFrameRejectBadVersion(t *testing.T) {
	header := make([]byte, frame.HeaderSize)
	header[0] = 2 // wrong version
	header[1] = frame.TypeData
	_, _, err := frame.Decode(header)
	if err == nil {
		t.Error("should reject bad version")
	}
}

func TestCBORRejectTruncated(t *testing.T) {
	// Truncated byte string: claims 32 bytes but only has 5
	data := []byte{0x58, 0x20, 0x01, 0x02, 0x03, 0x04, 0x05}
	_, _, err := cbor.Decode(data)
	if err == nil {
		t.Error("should reject truncated byte string")
	}
}

func TestCBORRejectHugeArray(t *testing.T) {
	// Array claiming 0xFFFFFFFF items but with no data
	data := []byte{0x9a, 0xff, 0xff, 0xff, 0xff}
	_, _, err := cbor.Decode(data)
	if err == nil {
		t.Error("should reject huge array with no data")
	}
}

// === Error code tests ===

func TestErrorCodesAlwaysFatal(t *testing.T) {
	fatalCodes := []uint32{2001, 2002, 2006, 2007, 8004, 8005, 8006, 8009}
	for _, code := range fatalCodes {
		if !aafperrors.IsAlwaysFatal(code) {
			t.Errorf("code %d should be always fatal", code)
		}
	}
	nonFatalCodes := []uint32{0, 1001, 4001, 5001, 8001, 9000}
	for _, code := range nonFatalCodes {
		if aafperrors.IsAlwaysFatal(code) {
			t.Errorf("code %d should NOT be always fatal", code)
		}
	}
}

// === Session ID derivation ===

func TestSessionIdDerivation(t *testing.T) {
	// Verify the session ID derivation is deterministic
	h := bytes32(0xaa) // placeholder transcript hash
	sid := handshake.ComputeSessionId(h, nonceA, nonceB, agentIDB)
	if len(sid) != 32 {
		t.Errorf("session ID length: %d, expected 32", len(sid))
	}
	// Same inputs must produce same output
	sid2 := handshake.ComputeSessionId(h, nonceA, nonceB, agentIDB)
	if string(sid) != string(sid2) {
		t.Error("session ID derivation is not deterministic")
	}
	// Different inputs must produce different output
	sid3 := handshake.ComputeSessionId(h, nonceB, nonceA, agentIDB)
	if string(sid) == string(sid3) {
		t.Error("session ID should differ when nonce order changes")
	}
}
